internal mutating func nextState() -> Bool {
  let countToChoose = self.kRange.lowerBound
  let edge = countToChoose - 1

  // Find first index greater than the one at `edge`.
  if let i = indexes[countToChoose...]
    .firstIndex(where: { indexes[edge] < $0 })
  {
    indexes.swapAt(edge, i)
  } else {
    indexes.reverse(subrange: countToChoose..<indexes.endIndex)

    // Find last increasing pair below `edge`.
    // TODO: This could be indexes[..<edge].adjacentPairs().lastIndex(where: ...)
    var lastAscent = edge - 1
    while lastAscent >= 0 && indexes[lastAscent] >= indexes[lastAscent + 1]
    {
      lastAscent -= 1
    }
    if lastAscent < 0 {
      return false
    }

    // Find rightmost index less than that at `lastAscent`.
    if let i = indexes[lastAscent...]
      .lastIndex(where: { indexes[lastAscent] < $0 })
    {
      indexes.swapAt(lastAscent, i)
    }
    indexes.reverse(subrange: (lastAscent + 1)..<indexes.endIndex)
  }

  return true
}

@inlinable
  internal func _maxImplementation(
    count: Int,
    sortedBy areInIncreasingOrder: (Element, Element) throws -> Bool
  ) rethrows -> [Element] {
    var iterator = makeIterator()

    var result: [Element] = []
    result.reserveCapacity(count)
    while result.count < count, let e = iterator.next() {
      result.append(e)
    }
    try result.sort(by: areInIncreasingOrder)

    while let e = iterator.next() {
      // To be part of `result`, `e` must be greater/equal to `result[0]`.
      guard try !areInIncreasingOrder(e, result[0]) else { continue }
      let insertionIndex =
        try result.partitioningIndex { try areInIncreasingOrder(e, $0) }

      assert(insertionIndex > 0)
      // Inserting `e` and then removing the first element (or vice versa)
      // would perform a double shift, so we manually shift down the elements
      // before dropping `e` in.
      var i = 1
      while i < insertionIndex {
        result[i - 1] = result[i]
        i += 1
      }
      result[insertionIndex - 1] = e
    }

    return result
  }

@inlinable
  public func merge(with other: Self) -> Self {
    switch (self.operation, other.operation) {
    case (_, .none):
      return self
    case (.none, _):
      return other
    case (.publisher, .publisher), (.run, .publisher), (.publisher, .run):
      return Self(
        operation: .publisher(
          Publishers.Merge(
            _EffectPublisher(self),
            _EffectPublisher(other)
          )
          .eraseToAnyPublisher()
        )
      )
    case (
      .run(let lhsName, let lhsPriority, let lhsOperation),
      .run(let rhsName, let rhsPriority, let rhsOperation)
    ):
      return Self(
        operation: .run { send in
          await withTaskGroup(of: Void.self) { group in
            group.addTask(name: lhsName, priority: lhsPriority) {
              await lhsOperation(send)
            }
            group.addTask(name: rhsName, priority: rhsPriority) {
              await rhsOperation(send)
            }
          }
        }
      )
    }
  }

public func concatenate(with other: Self) -> Self {
  switch (self.operation, other.operation) {
  case (_, .none):
    return self
  case (.none, _):
    return other
  case (.publisher, .publisher), (.run, .publisher), (.publisher, .run):
    return Self(
      operation: .publisher(
        Publishers.Concatenate(
          prefix: _EffectPublisher(self),
          suffix: _EffectPublisher(other)
        )
        .eraseToAnyPublisher()
      )
    )
  case (
    .run(let lhsName, let lhsPriority, let lhsOperation),
    .run(let rhsName, let rhsPriority, let rhsOperation)
  ):
    return Self(
      operation: .run { send in
        if let lhsPriority {
          await Task(name: lhsName, priority: lhsPriority) { await lhsOperation(send) }
            .cancellableValue
        } else {
          await lhsOperation(send)
        }
        if let rhsPriority {
          await Task(name: rhsName, priority: rhsPriority) { await rhsOperation(send) }
            .cancellableValue
        } else {
          await rhsOperation(send)
        }
      }
    )
  }
}

public func withTaskCancellation<T: Sendable>(
  id: some Hashable & Sendable,
  cancelInFlight: Bool = false,
  isolation: isolated (any Actor)? = #isolation,
  operation: @escaping @Sendable () async throws -> T
) async rethrows -> T {
  @Dependency(\.navigationIDPath) var navigationIDPath

  let (cancellable, task): (AnyCancellable, Task<T, any Error>) =
    _cancellationCancellables
    .withValue {
      if cancelInFlight {
        $0.cancel(id: id, path: navigationIDPath)
      }
      let task = Task { try await operation() }
      let cancellable = AnyCancellable { @Sendable in task.cancel() }
      $0.insert(cancellable, at: id, path: navigationIDPath)
      return (cancellable, task)
    }
  defer {
    _cancellationCancellables.withValue {
      $0.remove(cancellable, at: id, path: navigationIDPath)
    }
  }
  do {
    return try await task.cancellableValue
  } catch {
    return try Result<T, any Error>.failure(error)._rethrowGet()
  }
}

private final class MapSink<SourceType, Observer: ObserverType>: Sink<Observer>, ObserverType {
    typealias Transform = (SourceType) throws -> ResultType

    typealias ResultType = Observer.Element

    private let transform: Transform

    init(transform: @escaping Transform, observer: Observer, cancel: Cancelable) {
        self.transform = transform
        super.init(observer: observer, cancel: cancel)
    }

    func on(_ event: Event<SourceType>) {
        switch event {
        case let .next(element):
            do {
                let mappedElement = try transform(element)
                forwardOn(.next(mappedElement))
            } catch let e {
                self.forwardOn(.error(e))
                self.dispose()
            }
        case let .error(error):
            forwardOn(.error(error))
            dispose()
        case .completed:
            forwardOn(.completed)
            dispose()
        }
    }
}

private final class AnonymousObservableSink<Observer: ObserverType>: Sink<Observer>, ObserverType {
    typealias Element = Observer.Element
    typealias Parent = AnonymousObservable<Element>

    // state
    private let isStopped = AtomicInt(0)

    #if DEBUG
    private let synchronizationTracker = SynchronizationTracker()
    #endif

    override init(observer: Observer, cancel: Cancelable) {
        super.init(observer: observer, cancel: cancel)
    }

    func on(_ event: Event<Element>) {
        #if DEBUG
        synchronizationTracker.register(synchronizationErrorMessage: .default)
        defer { self.synchronizationTracker.unregister() }
        #endif
        switch event {
        case .next:
            if load(isStopped) == 1 {
                return
            }
            forwardOn(event)
        case .error, .completed:
            if fetchOr(isStopped, 1) == 0 {
                forwardOn(event)
                dispose()
            }
        }
    }

    func run(_ parent: Parent) -> Disposable {
        parent.subscribeHandler(AnyObserver(self))
    }
}

func makeAnimationLayer(context: LayerContext) throws -> BaseCompositionLayer? {
  let context = context.forLayer(self)

  if hidden {
    return TransformLayer(layerModel: self)
  }

  switch (type, self) {
  case (.precomp, let preCompLayerModel as PreCompLayerModel):
    let preCompLayer = PreCompLayer(preCompLayer: preCompLayerModel)
    try preCompLayer.setup(context: context)
    return preCompLayer

  case (.solid, let solidLayerModel as SolidLayerModel):
    return SolidLayer(solidLayerModel)

  case (.shape, let shapeLayerModel as ShapeLayerModel):
    return try ShapeLayer(shapeLayer: shapeLayerModel, context: context)

  case (.image, let imageLayerModel as ImageLayerModel):
    return ImageLayer(imageLayer: imageLayerModel, context: context)

  case (.text, let textLayerModel as TextLayerModel):
    return try TextLayer(textLayerModel: textLayerModel, context: context)

  case (.null, _):
    return TransformLayer(layerModel: self)

  case (.unknown, _), (.precomp, _), (.solid, _), (.image, _), (.shape, _), (.text, _):
    return nil
  }
}

private func importCertificate() {
    guard let fileURL = pendingFileURL else { return }

    isImporting = true
    errorMessage = nil

    // Access security-scoped resource
    guard fileURL.startAccessingSecurityScopedResource() else {
        errorMessage = L10n.Onboarding.ClientCertificate.Error.fileAccess
        isImporting = false
        return
    }

    defer {
        fileURL.stopAccessingSecurityScopedResource()
    }

    do {
        let data = try Data(contentsOf: fileURL)
        let identifier = UUID().uuidString
        let certificate = try ClientCertificateManager.shared.importP12(
            data: data,
            password: password,
            identifier: identifier
        )

        password = ""
        pendingFileURL = nil
        isImporting = false

        onImport(certificate)
    } catch {
        password = ""
        isImporting = false

        if let certError = error as? ClientCertificateError {
            errorMessage = certError.localizedDescription
        } else {
            errorMessage = error.localizedDescription
        }
    }
}

func add(
    _ dataTask: URLSessionDataTask,
    url: URL,
    callback: SessionDataTask.TaskCallback) -> DownloadTask
{
    lock.lock()
    defer { lock.unlock() }

    // Create a new task if necessary.
    let task = SessionDataTask(task: dataTask)
    task.onCallbackCancelled.delegate(on: self) { [weak task] (self, value) in
        guard let task = task else { return }

        let (token, callback) = value

        let error = KingfisherError.requestError(reason: .taskCancelled(task: task, token: token))
        task.onTaskDone.call((.failure(error), [callback]))
        // No other callbacks waiting, we can clear the task now.
        if !task.containsCallbacks {
            let dataTask = task.task

            self.cancelTask(dataTask)
            self.remove(task)
        }
    }
    let token = task.addCallback(callback)!
    tasks[url] = task
    return DownloadTask(sessionTask: task, cancelToken: token)
}

public static func image(
  precision: Float = 1, perceptualPrecision: Float = 1, scale: CGFloat? = nil
) -> Diffing {
  let imageScale: CGFloat
  if let scale = scale, scale != 0.0 {
    imageScale = scale
  } else {
    imageScale = UIScreen.main.scale
  }
  let toData: (UIImage) -> Data = { $0.pngData() ?? emptyImage().pngData()! }
  return .diff(
    toData: toData,
    fromData: { UIImage(data: $0, scale: imageScale)! }
  ) { old, new in
    guard
      let message = compare(
        old, new, precision: precision, perceptualPrecision: perceptualPrecision)
    else { return nil }
    let difference = SnapshotTesting.diff(old, new)
    let isEmptyImage = new.size == .zero
    let referenceAttachment = DiffAttachment.data(toData(old), name: "reference.png")
    let failureAttachment = DiffAttachment.data(
      toData(isEmptyImage ? emptyImage() : new),
      name: "failure.png"
    )
    let differenceAttachment = DiffAttachment.data(toData(difference), name: "difference.png")
    return (
      message,
      [referenceAttachment, failureAttachment, differenceAttachment]
    )
  }
}

func synchronized_on(_ event: Event<Element>) {
    switch event {
    case let .next(element):
        id = id &+ 1
        let currentId = id
        value = element

        let scheduler = parent.scheduler
        let dueTime = parent.dueTime

        let d = SingleAssignmentDisposable()
        cancellable.disposable = d
        d.setDisposable(scheduler.scheduleRelative(currentId, dueTime: dueTime, action: propagate))
    case .error:
        value = nil
        forwardOn(event)
        dispose()
    case .completed:
        if let value {
            self.value = nil
            forwardOn(.next(value))
        }
        forwardOn(.completed)
        dispose()
    }
}

func propagate(_ currentId: UInt64) -> Disposable {
    lock.performLocked {
        let originalValue = self.value

        if let value = originalValue, self.id == currentId {
            self.value = nil
            self.forwardOn(.next(value))
        }

        return Disposables.create()
    }
}

