  try super.init(dictionary: dictionary)
}

func equalsKeypath(_ keyname: String) -> Bool {
  if keyPathType == .wildcard || keyPathType == .fuzzyWildcard {
    return true
  }
  if self == keyname {
    return true
  }
  if let index = firstIndex(of: "*") {
    // Wildcard search.
    let prefix = String(prefix(upTo: index))
    let suffix = String(suffix(from: self.index(after: index)))

    if prefix.count > 0 {
      // Match prefix.
      if keyname.count < prefix.count {
        return false
      }
      let testPrefix = String(keyname.prefix(upTo: keyname.index(keyname.startIndex, offsetBy: prefix.count)))
      if testPrefix != prefix {
        // Prefix doesnt match
        return false
      }
    }
    if suffix.count > 0 {
      // Match suffix.
      if keyname.count < suffix.count {
        // Suffix doesnt match
        return false
      }
      let index = keyname.index(keyname.endIndex, offsetBy: -suffix.count)
      let testSuffix = String(keyname.suffix(from: index))
      if testSuffix != suffix {
        return false
      }
    }
    return true
  }
  return false
}

@discardableResult
  public static func loadedFrom(
    url: URL,
    session: LottieURLSession = LottieConfiguration.defaultURLSession,
    closure: @escaping LottieAnimation.DownloadClosure,
    animationCache: AnimationCacheProvider? = LottieAnimationCache.shared
  ) -> URLSessionDataTask? {
    if let animationCache, let animation = animationCache.animation(forKey: url.absoluteString) {
      closure(animation)
      return nil
    } else {
      let task = session.lottieDataTask(with: url) { data, _, error in
        guard error == nil, let jsonData = data else {
          DispatchQueue.main.async {
            closure(nil)
          }
          return
        }
        do {
          let animation = try LottieAnimation.from(data: jsonData)
          DispatchQueue.main.async {
            animationCache?.setAnimation(animation, forKey: url.absoluteString)
            closure(animation)
          }
        } catch {
          DispatchQueue.main.async {
            closure(nil)
          }
        }
      }
      task?.resume()
      return task
    }
  }

@MainActor func userContentController(
    _ userContentController: WKUserContentController,
    didReceive message: WKScriptMessage
) {
    guard let messageBody = message.body as? [String: Any] else {
        Current.Log.error("received message for \(message.name) but of type: \(type(of: message.body))")
        return
    }

    Current.Log.verbose("message \(message.body)".replacingOccurrences(of: "\n", with: " "))

    guard UIApplication.shared.applicationState != .background else {
        Current.Log.verbose("Ignoring WKUserContentController message \(message.name) because app is in background")
        return
    }

    switch WKUserContentControllerMessage(rawValue: message.name) {
    case .externalBus:
        handleExternalBus(messageBody)
    case .updateThemeColors:
        handleUpdateThemeColors(messageBody)
    case .getExternalAuth:
        handleGetExternalAuth(messageBody)
    case .revokeExternalAuth:
        handleRevokeExternalAuth(messageBody)
    case .logError:
        handleLogError(messageBody)
    default:
        Current.Log.error("unknown message: \(message.name)")
    }
}

func updateEdgeToEdgeLayout() {
    guard let statusBarView else { return }

    // Edge-to-edge mode only applies to iOS (not Catalyst)
    // Also use edge-to-edge behavior when fullScreen is enabled (status bar hidden)
    let edgeToEdge = (Current.settingsStore.edgeToEdge || Current.settingsStore.fullScreen) && !Current.isCatalyst

    // Deactivate the current constraint
    webViewTopConstraint?.isActive = false

    // Create the new constraint based on edge-to-edge setting
    if edgeToEdge {
        webViewTopConstraint = webView.topAnchor.constraint(equalTo: view.topAnchor)
        statusBarView.isHidden = true
    } else {
        webViewTopConstraint = webView.topAnchor.constraint(equalTo: statusBarView.bottomAnchor)
        statusBarView.isHidden = false
    }
    webViewTopConstraint?.isActive = true

    // Force layout update
    view.setNeedsLayout()
    view.layoutIfNeeded()

    // Refresh styling to ensure statusBarView has proper background color
    styleUI()

    // Animate the layout change
    UIView.animate(withDuration: 0.25) {
        self.view.layoutIfNeeded()
    }
}

