func webView(_ webView: WKWebView, didFailProvisionalNavigation navigation: WKNavigation!, withError error: Error) {
    refreshControl.endRefreshing()

    let nsError = error as NSError
    let shouldShowError: Bool

    // Handle URLError
    if let urlError = error as? URLError {
        shouldShowError = urlError.code != .cancelled
        if shouldShowError {
            Current.Log.error("Failure during content load: \(error)")
        }
    }
    // Handle WebKitErrorDomain errors (e.g., Code 101 - invalid URL)
    else if nsError.domain == "WebKitErrorDomain" {
        shouldShowError = !nsError.isCancelled
        Current.Log.error("WebKit error during content load: \(error)")
    } else {
        shouldShowError = !error.isCancelled
        if shouldShowError {
            Current.Log.error("Failure during content load: \(error)")
        }
    }

    if shouldShowError {
        latestLoadError = error
        showEmptyState()
    }
}

private func presentTestFlightMessageIfNeeded(
    over webViewController: WebViewController,
    attempt: Int = 0
) {
    guard !didPresentTestFlightMessage else { return }
    let engine = TestFlightCommunicationEngine()
    guard let message = engine.messageToShow() else { return }

    DispatchQueue.main.asyncAfter(deadline: .now() + TestFlightCommunicationConstants.retryDelay) { [
        weak self,
        weak webViewController
    ] in
        guard let self, let webViewController, !didPresentTestFlightMessage else { return }

        guard webViewController.viewIfLoaded?.window != nil,
              webViewController.overlayedController == nil else {
            if attempt < TestFlightCommunicationConstants.retryLimit {
                presentTestFlightMessageIfNeeded(over: webViewController, attempt: attempt + 1)
            }
            return
        }

        didPresentTestFlightMessage = true
        let controller = TestFlightCommunicationView(message: message) {
            engine.markSeen(message)
        }.embeddedInHostingController()
        controller.modalPresentationStyle = .formSheet
        webViewController.presentOverlayController(controller: controller, animated: true)
    }
}

public func disableKioskMode() {
    guard isKioskModeActive else { return }

    Current.Log.info("Disabling kiosk mode")
    isKioskModeActive = false

    // Persist disabled state
    if settings.isKioskModeEnabled {
        var updated = settings
        updated.isKioskModeEnabled = false
        settings = updated
    }

    // Restore original brightness
    if let original = originalBrightness {
        Current.setScreenBrightness(CGFloat(original))
    }

    // Re-enable iOS auto-lock if kiosk mode had disabled it
    if settings.preventAutoLock {
        Current.application?().isIdleTimerDisabled = false
        Current.Log.info("Screen auto-lock restored")
    }

    // Stop timers
    stopIdleTimer()
    stopPixelShiftTimer()

    // Hide screensaver if active
    hideScreensaver(source: "kiosk_disabled")

    // Tear down the secret-exit gesture overlay so its child VC + UIHostingController stop
    // covering the WebView.
    tearDownSecretExitGesture()

    updateKioskModeLockdown(enabled: false)
    notifyObserversOfModeChange()
}

private func settingsDidChange(from oldValue: KioskSettings, to newValue: KioskSettings) {
    guard isKioskModeActive else {
        notifyObserversOfSettingsChange()
        return
    }

    // Reapply brightness if setting changed
    if oldValue.manualBrightness != newValue.manualBrightness {
        applyBrightness()
    }

    // Restart idle timer if timeout changed
    if oldValue.screensaverTimeout != newValue.screensaverTimeout,
       screenState == .on {
        startIdleTimer()
    }

    // Apply preventAutoLock changes immediately
    if oldValue.preventAutoLock != newValue.preventAutoLock {
        Current.application?().isIdleTimerDisabled = newValue.preventAutoLock
    }

    // Apply screensaver enabled/disabled changes immediately
    if oldValue.screensaverEnabled != newValue.screensaverEnabled {
        if newValue.screensaverEnabled {
            if screenState == .on {
                startIdleTimer()
            }
        } else {
            stopIdleTimer()
        }
    }

    updateKioskModeLockdown(enabled: true)
    notifyObserversOfSettingsChange()
}

func attemptKioskExit() {
    let authSettings = manager.settings
    guard authSettings.requireDeviceAuthentication else {
        manager.disableKioskMode()
        return
    }

    let context = LAContext()
    var error: NSError?

    guard context.canEvaluatePolicy(.deviceOwnerAuthentication, error: &error) else {
        manager.disableKioskMode()
        return
    }

    let reason = L10n.Kiosk.AuthError.reason
    context.evaluatePolicy(.deviceOwnerAuthentication, localizedReason: reason) { success, authError in
        DispatchQueue.main.async { [weak self] in
            if success {
                self?.manager.disableKioskMode()
            } else if let authError = authError as? LAError {
                switch authError.code {
                case .userCancel, .appCancel:
                    break
                default:
                    self?.authErrorMessage = authError.localizedDescription
                    self?.showingAuthError = true
                }
            }
        }
    }
}

func authenticateForSettings() {
    let context = LAContext()
    var error: NSError?
    let authSettings = manager.settings

    guard authSettings.requireDeviceAuthentication else {
        isAuthenticated = true
        return
    }

    guard context.canEvaluatePolicy(.deviceOwnerAuthentication, error: &error) else {
        isAuthenticated = true
        return
    }

    let reason = L10n.Kiosk.AuthError.reason
    context.evaluatePolicy(.deviceOwnerAuthentication, localizedReason: reason) { success, authError in
        DispatchQueue.main.async { [weak self] in
            if success {
                self?.isAuthenticated = true
            } else if let authError = authError as? LAError {
                switch authError.code {
                case .userCancel, .appCancel:
                    break
                default:
                    self?.authErrorMessage = authError.localizedDescription
                    self?.showingAuthError = true
                }
            }
        }
    }
}

private func configuredAPI(
    authDetails: OnboardingAuthDetails,
    instance: DiscoveredHomeAssistant,
    code: String
) -> Promise<HomeAssistantAPI> {
    Current.Log.info()

    var connectionInfo = ConnectionInfo(discovered: instance, authDetails: authDetails)

    return tokenExchange.tokenInfo(
        code: code,
        connectionInfo: &connectionInfo
    ).then { tokenInfo -> Promise<HomeAssistantAPI> in
        Current.Log.verbose()

        var serverInfo = ServerInfo(
            name: ServerInfo.defaultName,
            connection: connectionInfo,
            token: tokenInfo,
            version: instance.version ?? DiscoveredHomeAssistant.defaultVersion
        )

        let identifier = Identifier<Server>(rawValue: instance.uuid ?? UUID().uuidString)
        let server = Server(
            identifier: identifier,
            getter: { serverInfo },
            setter: { serverInfo = $0; return true }
        )

        return .value(HomeAssistantAPI(server: server))
    }
}
